var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"무엇을 보고 있니?","JPN":"何を見ているの？","ENG":"What are you looking at?","TWN":"你在看什麼？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"달을 보고 있습니다.","JPN":"お月様を眺めていました。","ENG":"I was looking at the moon.","TWN":"我在看月亮。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"밑에서 볼 땐 작은 경단 같았는데, 여기서 보니 정말 크고 둥글어요.","JPN":"下から見た時は小さなお団子みたいだったのに、\\nここから見ると丸くて大きいですね。","ENG":"It looked like a little ball of dango from below, but it’s really big and round when you look at it from here.","TWN":"在底下看的時候，像個小糯米糰，在這裡一看，真的是又大又圓呢。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"그래, 예쁘구나.","JPN":"そうね、とても綺麗だわ。","ENG":"Yes, it is pretty.","TWN":"是啊，很漂亮。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"여기서는 참 많은 것들이 또렷하게 보이는 것 같아.","JPN":"ここから眺めると、いろんなものがはっきり見えるわね。","ENG":"Everything is so crystal clear when you look at them from here.","TWN":"在這裡能看清楚很多東西。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"바람이 찬데, 녹차 마실래?","JPN":"風が冷たいわね。温かいお茶でも飲む？","ENG":"The wind is cold. Do you want some green tea?","TWN":"風有點涼，要來杯綠茶嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"네, 감사합니다.","JPN":"はい、ありがとうございます。","ENG":"Yes, thank you.","TWN":"好，謝謝。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"우읏……. 써.","JPN":"ううっ……苦い。","ENG":"Urgh... It’s bitter.","TWN":"唔……好苦。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"후훗. 입맛에 잘 안 맞나 보구나. 물을 더 넣어 줄게.","JPN":"ふふっ、あなたには濃すぎたかしら？　お湯を足してあげるわ。","ENG":"Hah hah, here, let me add some more water.","TWN":"呵呵，看來不合你胃口，我再給你加點水吧。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"괜찮습니다. 인생을 살아가려면 쓴 맛도 즐길 줄 알아야 하는 법이니까요.","JPN":"大丈夫です。\\n人生を生きていくには苦味も楽しまなければならないですから。","ENG":"It’s okay. Life is bitter, and I should learn how to enjoy the bitterness.","TWN":"沒關係，人生在世也要懂得享受苦味。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"어머, 그런 말은 어디서 배웠니?","JPN":"あら、そんな言葉どこで覚えてきたの？","ENG":"Oh, where did you hear that?","TWN":"哎唷，這些話是從哪裡學的？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"나나하라 당주님께서 가르쳐 주셨습니다.","JPN":"七原家のご当主様が教えてくださいました。","ENG":"From Lady Nanahara.","TWN":"是七原堂主教我的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"그 분은 또 애한테 이상한 걸 가르치셨네…….","JPN":"あのお方ったら、子どもに変なことを教えちゃって……","ENG":"That’s a strange thing to say to a child.","TWN":"堂主又教孩子一些奇怪的東西……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"그래도 기억해 두면 언젠가 도움이 되겠지. 실없는 소릴 하는 분은 아니니까.","JPN":"まあでも、覚えておけばいつか役に立つかもしれないわね。\\nくだらないことを口にするようなお方じゃないから。","ENG":"But everything she does is for a reason, so I suppose she meant you good.","TWN":"我只是說說而已，堂主教你的你要記得，她不是會胡亂說話的人，總有一天會派上用場的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"네, 어머니.","JPN":"はい、母上。","ENG":"Yes, mother.","TWN":"好的，媽媽。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"부전대장님, 이만 가실 시간입니다.","JPN":"副戦隊長、そろそろお時間でございます。","ENG":"Deputy Commander, it’s time to go.","TWN":"副戰隊長，該出發了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"네~ 금방 가요~","JPN":"はーい、すぐに行きまーす。","ENG":"Yes, I’ll be right there.","TWN":"好~ 馬上來~"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"……이번에 가면 언제 돌아오시는 겁니까?","JPN":"……今回の戦に出られたら、次はいつお戻りになるのですか？","ENG":"When are you coming back?","TWN":"……這次離開後什麼時候會回來？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"조금 오래 걸리겠지만 안심하렴. 이번이 마지막일 거란다.","JPN":"少し長くなるけど心配しないで。これで戦は終わりだろうから。","ENG":"It will take some time. But don’t worry. This will be my last mission.","TWN":"可能會需要滿長一段時間，不過你放心，這次應該是最後一次。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"나나하라 당주님께서 뱀을 잠재우실 테니까.","JPN":"七原家当主が蛇を眠らせるの。","ENG":"Lady Nanahara will put the snake to sleep forever this time.","TWN":"因爲七原堂主會讓蛇沈睡的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"그럼 세상도 평화로워지고, 이 엄마는 무직 백수 전업주부가 될 거야.","JPN":"そうすれば世の中が平和になって、母は専業主婦になると思うわ。","ENG":"Then the world will be at peace, and I’ll become an ordinary housewife.","TWN":"世界也會因此變和平，而媽媽則會變成全職家庭主婦。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"그 때는 사나에와도 하루 종일 같이 시간을 보낼 수 있겠지.","JPN":"そうすれば、早苗と一日中一緒に過ごせるわね。","ENG":"When the day comes, I’ll be able to have fun with you all day, everyday.","TWN":"到時候就可以整天陪早苗囉。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"맛있는 간식도 많이 만들어서 먹고, 뜨개질도 같이 배우고, 검술도 가르쳐 주고.","JPN":"美味しいおやつをたくさん作って、一緒に編み物をして、剣術も教えてあげる。","ENG":"I’ll cook you a delicious dish, teach you how to knit, and how to wield a sword.","TWN":"我們可以一起做很多好吃的點心來吃，一起學習做針線活，還有劍術。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"아.","JPN":"あっ。","ENG":"Oh.","TWN":"哎呀！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"마지막 건 취소. 당주님이 너 열 살 되기 전까진 싸우는 거 가르치지 말라고 했거든.","JPN":"剣術はまだダメね。ご当主様があなたが10歳になるまでは\\n戦を教えるなとおっしゃっていたから。","ENG":"Scratch that last part. Lady Nanahara told me not to teach you swordsmanship until you’re ten.","TWN":"最後一樣取消，堂主說在你10歲前不要教你武功。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"괜찮아요. 이렇게 듣기만 해도 좋은걸요.","JPN":"大丈夫です。私はこうして母上とお話するだけで嬉しいです。","ENG":"It’s okay. I love to hear you just like this.","TWN":"沒關係，光想就覺得開心。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"그럼 돌아오실 때까지 착하게 기다리겠습니다.","JPN":"お戻りになるまでいい子にして待っています。","ENG":"I’ll be a good girl and wait for your return.","TWN":"那我會乖乖等媽媽回來。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"어머니를 위해 달님께 기도할 겁니다.","JPN":"母上のためにお月様にお祈りも捧げます。","ENG":"I’ll pray to the moon for your safety.","TWN":"我會向月亮祈禱，讓媽媽平安回來。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"고맙구나.","JPN":"ありがとう。","ENG":"Thank you.","TWN":"謝謝你。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_QM","text":{"KOREA":"널 볼 때마다, 당주님 말씀이 옳았다는 걸 느낀단다.","JPN":"あなたを見るたびに、ご当主様の言葉は正しかったと実感するわ。","ENG":"Whenever I see you, I realize that Lady Nanahara was right.","TWN":"每次看到你，就覺得堂主的話沒錯。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"<b>가족이 있다는 건, 참으로 좋은 것이라고 말이다.</b>","JPN":"<b>家族がいるということは、実に素晴らしいことだ。</b>","ENG":"<b>It’s good to have a family.</b>","TWN":"<b>有家人，真的是一件很棒的事。</b>"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"어머니는 당주님을 부모처럼 섬기고, 친구처럼 대하시는 분이었다.","JPN":"母上にとってご当主様は親のように敬う存在であり、\\n友のように接することができるお方だった。","ENG":"My mother served Lady Nanahara like a parent and got along with her like friends.","TWN":"家母服侍堂主就像服侍父母一樣，相處起來又像朋友一樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"장난을 좋아하지만 가식이 없고, 친근하면서도 겸손했기에 주변에도 사람이 많았다.","JPN":"無邪気で飾らず、親しみやすいが謙虚な性格だったので\\n周囲の人々から愛されていた。","ENG":"She was playful, friendly, and humble—everyone liked her.","TWN":"雖然很喜歡開玩笑，但她不虛僞，為人親切又謙虛，因此身邊常常有很多人圍繞著她。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 더더욱.","JPN":"だからこそ、","ENG":"Which made it even more difficult...","TWN":"所以。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"그 사람의 마지막을 받아들일 수 없었다.","JPN":"その人の最期を受け入れることができなかった。","ENG":"... for me to accept her end.","TWN":"更加無法接受她的下場。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};